  1→import fs from "fs/promises";
  2→import path from "path";
  3→import crypto from "crypto";
  4→import mime from "mime-types";
  5→import pino from "pino";
  6→import qrcode from "qrcode-terminal";
  7→import makeWASocket, {
  8→  DisconnectReason,
  9→  downloadMediaMessage,
 10→  fetchLatestBaileysVersion,
 11→  useMultiFileAuthState,
 12→} from "@whiskeysockets/baileys";
 13→import { compactTimestamp } from "../tools/common.js";
 14→import {
 15→  makeInboundReplyKey,
 16→  makeReplyContentKey,
 17→  resolveReplyTargets,
 18→  sleep,
 19→} from "./reply-router.js";
 20→
 21→function unwrapMessageContainer(message) {
 22→  if (!message) return null;
 23→  if (message.ephemeralMessage?.message) {
 24→    return message.ephemeralMessage.message;
 25→  }
 26→  if (message.viewOnceMessage?.message) {
 27→    return message.viewOnceMessage.message;
 28→  }
 29→  return message;
 30→}
 31→
 32→function extractTextContent(message) {
 33→  const m = unwrapMessageContainer(message);
 34→  if (!m) return "";
 35→  if (m.conversation) return m.conversation;
 36→  if (m.extendedTextMessage?.text) return m.extendedTextMessage.text;
 37→  if (m.imageMessage?.caption) return m.imageMessage.caption;
 38→  if (m.documentMessage?.caption) return m.documentMessage.caption;
 39→  if (m.videoMessage?.caption) return m.videoMessage.caption;
 40→  return "";
 41→}
 42→
 43→function makeFileNameFromMime(messageId, contentType, mediaMime) {
 44→  const extFromMime = mime.extension(mediaMime || "") || null;
 45→  const ext = extFromMime || (contentType === "image" ? "jpg" : "bin");
 46→  return `${compactTimestamp()}_${messageId}.${ext}`;
 47→}
 48→
 49→function normalizeText(text) {
 50→  return String(text || "")
 51→    .trim()
 52→    .replace(/\s+/g, " ")
 53→    .toLowerCase();
 54→}
 55→
 56→function makeChatMessageKey(chatJid, messageId) {
 57→  return `${chatJid || "unknown"}:${messageId || "unknown"}`;
 58→}
 59→
 60→function makeTextFingerprint(chatJid, text) {
 61→  const normalized = normalizeText(text);
 62→  if (!normalized) return null;
 63→  return crypto
 64→    .createHash("sha256")
 65→    .update(`${chatJid || "unknown"}|${normalized}`)
 66→    .digest("hex");
 67→}
 68→
 69→function withTimeout(promise, ms, label = "operation") {
 70→  let timer = null;
 71→  return Promise.race([
 72→    promise,
 73→    new Promise((_, reject) => {
 74→      timer = setTimeout(() => {
 75→        reject(new Error(`${label} timed out after ${ms}ms`));
 76→      }, ms);
 77→    }),
 78→  ]).finally(() => {
 79→    if (timer) clearTimeout(timer);
 80→  });
 81→}
 82→
 83→function textPreview(text, maxLength = 80) {
 84→  const clean = String(text || "").replace(/\s+/g, " ").trim();
 85→  if (!clean) return "(empty)";
 86→  return clean.length <= maxLength ? clean : `${clean.slice(0, maxLength)}...`;
 87→}
 88→
 89→export class WhatsAppHandler {
 90→  constructor({ config, logger, agent }) {
 91→    this.config = config;
 92→    this.logger = logger;
 93→    this.agent = agent;
 94→    this.socket = null;
 95→    this.reconnectInProgress = false;
 96→    this.processedMessageCache = new Map();
 97→    this.botMessageIdCache = new Map();
 98→    this.botMessageTextCache = new Map();
 99→    this.outboundEchoObservedCache = new Map();
100→    this.inboundReplyCompletedCache = new Map();
101→    this.outboundContentPerInboundCache = new Map();
102→    this.chatQueues = new Map();
103→    this.sentMessageStore = new Map();
104→  }
105→
106→  async start() {
107→    await this.connect();
108→  }
109→
110→  async connect() {
111→    if (this.reconnectInProgress) return;
112→    this.reconnectInProgress = true;
113→    try {
114→      const { state, saveCreds } = await useMultiFileAuthState(
115→        this.config.paths.waSession,
116→      );
117→      const { version } = await fetchLatestBaileysVersion();
118→      this.socket = makeWASocket({
119→        version,
120→        auth: state,
121→        browser: ["Teacher GradeBot", "Terminal", "1.0.0"],
122→        logger: pino({ level: "silent" }),
123→        syncFullHistory: false,
124→        getMessage: async (key) => {
125→          const storeKey = `${key.remoteJid}::${key.id}`;
126→          return this.sentMessageStore.get(storeKey) || undefined;
127→        },
128→      });
129→
130→      this.socket.ev.on("creds.update", saveCreds);
131→      this.socket.ev.on("connection.update", async (update) => {
132→        const { connection, lastDisconnect, qr } = update;
133→        if (qr) {
134→          this.logger.info("New WhatsApp QR received. Scan it with WhatsApp.");
135→          qrcode.generate(qr, { small: true });
136→        }
137→        if (connection === "open") {
138→          const meId = this.socket?.user?.id || "unknown";
139→          const meLid = this.socket?.user?.lid || "unknown";
140→          this.logger.info(`WhatsApp connected. meId=${meId} meLid=${meLid}`);
141→        } else if (connection === "close") {
142→          const statusCode =
143→            lastDisconnect?.error?.output?.statusCode ||
144→            lastDisconnect?.error?.statusCode;
145→          const shouldReconnect =
146→            statusCode !== DisconnectReason.loggedOut &&
147→            statusCode !== 401 &&
148→            statusCode !== 403;
149→          this.logger.warn(
150→            `WhatsApp disconnected. status=${statusCode || "unknown"} reconnect=${shouldReconnect}`,
151→          );
152→          if (shouldReconnect) {
153→            setTimeout(() => {
154→              this.connect().catch((error) => {
155→                this.logger.error(`Reconnect failed: ${error.message}`);
156→              });
157→            }, 2000);
158→          } else {
159→            this.logger.error(
160→              "Session logged out. Delete data/wa-session and restart for a new QR login.",
161→            );
162→          }
163→        }
164→      });
165→
166→      this.socket.ev.on("messages.upsert", async (upsert) => {
167→        const messageCount = (upsert.messages || []).length;
168→        this.logger.info(
169→          `messages.upsert received: type=${upsert.type} count=${messageCount}`,
170→        );
171→        if (!["notify", "append"].includes(upsert.type)) return;
172→        const tasks = [];
173→        for (const msg of upsert.messages || []) {
174→          if (this.observeOutgoingEchoFromUpsert(msg)) {
175→            continue;
176→          }
177→          tasks.push(
178→            this.enqueueByChat(msg?.key?.remoteJid, () =>
179→              this.handleIncomingMessage(msg),
180→            ),
181→          );
182→        }
183→        await Promise.allSettled(tasks);
184→      });
185→    } finally {
186→      this.reconnectInProgress = false;
187→    }
188→  }
189→
190→  enqueueByChat(chatJid, handler) {
191→    const key = chatJid || "unknown";
192→    const prior = this.chatQueues.get(key) || Promise.resolve();
193→    const next = prior
194→      .catch(() => undefined)
195→      .then(handler)
196→      .catch((error) => {
197→        this.logger.error(
198→          `Chat queue handler failed for ${key}: ${error.message || error}`,
199→        );
200→      })
201→      .finally(() => {
202→        if (this.chatQueues.get(key) === next) {
203→          this.chatQueues.delete(key);
204→        }
205→      });
206→    this.chatQueues.set(key, next);
207→    return next;
208→  }
209→
210→  observeOutgoingEchoFromUpsert(baileysMsg) {
211→    const chatJid = baileysMsg?.key?.remoteJid;
212→    const messageId = baileysMsg?.key?.id;
213→    if (!baileysMsg?.key?.fromMe || !chatJid || !messageId) {
214→      return false;
215→    }
216→
217→    const key = makeChatMessageKey(chatJid, messageId);
218→    if (!this.cacheHas(this.botMessageIdCache, key)) {
219→      return false;
220→    }
221→
222→    this.markOutboundEchoObserved(chatJid, messageId);
223→    this.logger.info(
224→      `Observed outbound echo immediately from upsert. outId=${messageId} chat=${chatJid}.`,
225→    );
226→    return true;
227→  }
228→
229→  pruneExpiredEntries(cache) {
230→    const now = Date.now();
231→    for (const [key, expiresAt] of cache.entries()) {
232→      if (!Number.isFinite(expiresAt) || expiresAt <= now) {
233→        cache.delete(key);
234→      }
235→    }
236→    const maxEntries = this.config.loopGuard.maxCacheEntries;
237→    if (cache.size <= maxEntries) return;
238→    const overflow = cache.size - maxEntries;
239→    let removed = 0;
240→    for (const key of cache.keys()) {
241→      cache.delete(key);
242→      removed += 1;
243→      if (removed >= overflow) break;
244→    }
245→  }
246→
247→  cacheSet(cache, key, ttlMs) {
248→    if (!key) return;
249→    const expiresAt = Date.now() + Math.max(1000, Number(ttlMs) || 1000);
250→    cache.set(key, expiresAt);
251→    this.pruneExpiredEntries(cache);
252→  }
253→
254→  cacheHas(cache, key) {
255→    if (!key) return false;
256→    const expiresAt = cache.get(key);
257→    if (!expiresAt) return false;
258→    if (expiresAt <= Date.now()) {
259→      cache.delete(key);
260→      return false;
261→    }
262→    return true;
263→  }
264→
265→  markOutboundEchoObserved(chatJid, messageId) {
266→    if (!chatJid || !messageId) return;
267→    this.cacheSet(
268→      this.outboundEchoObservedCache,
269→      makeChatMessageKey(chatJid, messageId),
270→      this.config.loopGuard.botMessageIdTtlMs,
271→    );
272→  }
273→
274→  hasOutboundEchoObserved(chatJid, messageId) {
275→    if (!chatJid || !messageId) return false;
276→    return this.cacheHas(
277→      this.outboundEchoObservedCache,
278→      makeChatMessageKey(chatJid, messageId),
279→    );
280→  }
281→
282→  hasInboundReplyCompleted(inboundKey) {
283→    return this.cacheHas(this.inboundReplyCompletedCache, inboundKey);
284→  }
285→
286→  markInboundReplyCompleted(inboundKey) {
287→    this.cacheSet(
288→      this.inboundReplyCompletedCache,
289→      inboundKey,
290→      this.config.loopGuard.processedMessageTtlMs,
291→    );
292→  }
293→
294→  async waitForDeliveryEvidence(chatJid, outboundMessageId) {
295→    if (!chatJid || !outboundMessageId) return false;
296→
297→    const timeoutMs = Math.max(0, this.config.replyRouting.verifyTimeoutMs || 0);
298→    if (this.hasOutboundEchoObserved(chatJid, outboundMessageId)) {
299→      return true;
300→    }
301→    if (timeoutMs <= 0) return false;
302→
303→    const deadline = Date.now() + timeoutMs;
304→    while (Date.now() < deadline) {
305→      if (this.hasOutboundEchoObserved(chatJid, outboundMessageId)) {
306→        return true;
307→      }
308→      await sleep(100);
309→    }
310→    return this.hasOutboundEchoObserved(chatJid, outboundMessageId);
311→  }
312→
313→  async sendReplyToTarget({ inboundKey, inboundMessageId, targetJid, replyText }) {
314→    const textHash = makeTextFingerprint(targetJid, replyText);
315→    const contentKey = makeReplyContentKey(inboundKey, targetJid, textHash);
316→    if (this.cacheHas(this.outboundContentPerInboundCache, contentKey)) {
317→      this.logger.info(
318→        `Reply dedupe skipped for inId=${inboundMessageId} target=${targetJid}.`,
319→      );
320→      return { skipped: true, targetJid };
321→    }
322→
323→    const sendResult = await this.socket.sendMessage(targetJid, { text: replyText });
324→    const outboundId = sendResult?.key?.id || "";
325→    this.rememberBotOutgoingMessage(targetJid, outboundId, replyText);
326→
327→    // Store for getMessage retry callback (Signal Protocol re-encryption)
328→    if (outboundId) {
329→      const storeKey = `${targetJid}::${outboundId}`;
330→      this.sentMessageStore.set(storeKey, { conversation: replyText });
331→      setTimeout(() => this.sentMessageStore.delete(storeKey), 5 * 60 * 1000);
332→    }
333→    this.cacheSet(
334→      this.outboundContentPerInboundCache,
335→      contentKey,
336→      this.config.loopGuard.processedMessageTtlMs,
337→    );
338→
339→    this.logger.info(
340→      `Reply send attempt success inId=${inboundMessageId} outId=${outboundId || "unknown"} target=${targetJid}.`,
341→    );
342→
343→    return {
344→      skipped: false,
345→      targetJid,
346→      outboundId,
347→      sendResult,
348→    };
349→  }
350→
351→  async sendReplyWithRouting({
352→    incomingJid,
353→    inboundMessageId,
354→    replyText,
355→    fromMe,
356→  }) {
357→    const inboundKey = makeInboundReplyKey(incomingJid, inboundMessageId);
358→    if (this.hasInboundReplyCompleted(inboundKey)) {
359→      this.logger.info(
360→        `Reply already completed for inId=${inboundMessageId}. Skipping duplicate send.`,
361→      );
362→      return { skipped: true, reason: "already_completed" };
363→    }
364→
365→    const meId = this.socket?.user?.id || "";
366→    const meLid = this.socket?.user?.lid || "";
367→    const routing = resolveReplyTargets({
368→      incomingJid,
369→      fromMe,
370→      meId,
371→      meLid,
372→      singleNumberMode: this.config.app.singleNumberMode,
373→      enableFallback: this.config.replyRouting.enableFallback,
374→      strategy: this.config.replyRouting.strategy,
375→    });
376→
377→    this.logger.info(
378→      `Reply routing inId=${inboundMessageId} strategy=${routing.strategy} reason=${routing.reason} primary=${routing.primary} fallbacks=[${routing.fallbacks.join(",") || "none"}].`,
379→    );
380→
381→    const targets = [routing.primary, ...routing.fallbacks].filter(Boolean);
382→    if (!targets.length) {
383→      throw new Error(
384→        `No valid reply target resolved for inId=${inboundMessageId}. incomingJid=${incomingJid}`,
385→      );
386→    }
387→    let lastError = null;
388→    let lastSuccess = null;
389→
390→    for (let i = 0; i < targets.length; i += 1) {
391→      const target = targets[i];
392→      if (this.hasInboundReplyCompleted(inboundKey)) {
393→        return {
394→          skipped: true,
395→          reason: "completed_during_send",
396→        };
397→      }
398→
399→      try {
400→        const attempt = await this.sendReplyToTarget({
401→          inboundKey,
402→          inboundMessageId,
403→          targetJid: target,
404→          replyText,
405→        });
406→        if (attempt.skipped) {
407→          continue;
408→        }
409→
410→        const hasFallback =
411→          this.config.replyRouting.enableFallback &&
412→          routing.fallbacks.length > 0 &&
413→          i === 0;
414→        let verified = true;
415→
416→        if (hasFallback) {
417→          verified = await this.waitForDeliveryEvidence(target, attempt.outboundId);
418→          this.logger.info(
419→            `Reply verify inId=${inboundMessageId} outId=${attempt.outboundId || "unknown"} target=${target} verified=${verified}.`,
420→          );
421→        }
422→
423→        lastSuccess = {
424→          ...attempt,
425→          usedFallback: i > 0,
426→          verified,
427→        };
428→
429→        if (verified || !hasFallback) {
430→          this.markInboundReplyCompleted(inboundKey);
431→          return lastSuccess;
432→        }
433→
434→        this.logger.warn(
435→          `No delivery evidence for primary target ${target} (inId=${inboundMessageId}). Trying fallback target.`,
436→        );
437→      } catch (error) {
438→        lastError = error;
439→        this.logger.error(
440→          `Reply send attempt failed inId=${inboundMessageId} target=${target}: ${error.message}`,
441→        );
442→      }
443→    }
444→
445→    if (lastSuccess) {
446→      this.markInboundReplyCompleted(inboundKey);
447→      return lastSuccess;
448→    }
449→
450→    throw lastError || new Error("Failed to send reply on all candidate targets.");
451→  }
452→
453→  rememberBotOutgoingMessage(chatJid, messageId, text) {
454→    const key = makeChatMessageKey(chatJid, messageId);
455→    this.cacheSet(
456→      this.botMessageIdCache,
457→      key,
458→      this.config.loopGuard.botMessageIdTtlMs,
459→    );
460→    const fingerprint = makeTextFingerprint(chatJid, text);
461→    this.cacheSet(
462→      this.botMessageTextCache,
463→      fingerprint,
464→      this.config.loopGuard.botMessageTextTtlMs,
465→    );
466→  }
467→
468→  shouldSkipAsDuplicate(chatJid, messageId) {
469→    const key = makeChatMessageKey(chatJid, messageId);
470→    if (this.cacheHas(this.processedMessageCache, key)) {
471→      return true;
472→    }
473→    this.cacheSet(
474→      this.processedMessageCache,
475→      key,
476→      this.config.loopGuard.processedMessageTtlMs,
477→    );
478→    return false;
479→  }
480→
481→  shouldSkipFromMeEcho(chatJid, messageId, text) {
482→    const messageKey = makeChatMessageKey(chatJid, messageId);
483→    const byId = this.cacheHas(this.botMessageIdCache, messageKey);
484→    const byText = this.cacheHas(
485→      this.botMessageTextCache,
486→      makeTextFingerprint(chatJid, text),
487→    );
488→    if (byId || byText) {
489→      this.markOutboundEchoObserved(chatJid, messageId);
490→    }
491→    return byId || byText;
492→  }
493→
494→  async handleIncomingMessage(baileysMsg) {
495→    try {
496→      if (!baileysMsg?.key?.remoteJid) return;
497→      if (baileysMsg.key.remoteJid === "status@broadcast") return;
498→
499→      const chatJid = baileysMsg.key.remoteJid;
500→      const messageId = baileysMsg.key.id || `${Date.now()}`;
501→      if (this.shouldSkipAsDuplicate(chatJid, messageId)) {
502→        this.logger.info(
503→          `Skipping duplicate event for message ${messageId} in ${chatJid}.`,
504→        );
505→        return;
506→      }
507→
508→      const normalizedMessage = unwrapMessageContainer(baileysMsg.message);
509→      const text = extractTextContent(baileysMsg.message);
510→
511→      if (baileysMsg.key.fromMe) {
512→        if (!this.config.app.singleNumberMode) {
513→          this.logger.info(
514→            `Skipping fromMe message ${messageId} from ${chatJid} because SINGLE_NUMBER_MODE=false.`,
515→          );
516→          return;
517→        }
518→        if (this.shouldSkipFromMeEcho(chatJid, messageId, text)) {
519→          this.logger.info(
520→            `Loop guard blocked bot-echo fromMe message ${messageId} in ${chatJid}.`,
521→          );
522→          return;
523→        }
524→        this.logger.info(
525→          `Accepted fromMe operator message ${messageId} in ${chatJid} (single-number mode).`,
526→        );
527→      }
528→
529→      const attachments = await this.extractAttachments(
530→        baileysMsg,
531→        normalizedMessage,
532→      );
533→
534→      this.logger.info(
535→        `Inbound message accepted from ${baileysMsg.key.remoteJid} (fromMe=${Boolean(baileysMsg.key.fromMe)} textPreview="${textPreview(text)}" attachments=${attachments.length}).`,
536→      );
537→
538→      const input = {
539→        userId: chatJid,
540→        messageId,
541→        text,
542→        attachments,
543→        timestamp: new Date(
544→          Number(baileysMsg.messageTimestamp || Math.floor(Date.now() / 1000)) *
545→            1000,
546→        ).toISOString(),
547→      };
548→
549→      const startedAt = Date.now();
550→      this.logger.info(
551→        `Agent handling started for message ${messageId} in ${chatJid}.`,
552→      );
553→      const result = await withTimeout(
554→        this.agent.handleIncoming(input),
555→        this.config.app.agentTimeoutMs,
556→        "agent.handleIncoming",
557→      );
558→      this.logger.info(
559→        `Agent handling completed for message ${messageId} in ${Date.now() - startedAt}ms.`,
560→      );
561→      if (result?.replyText) {
562→        const routed = await this.sendReplyWithRouting({
563→          incomingJid: chatJid,
564→          inboundMessageId: messageId,
565→          replyText: result.replyText,
566→          fromMe: Boolean(baileysMsg.key.fromMe),
567→        });
568→        this.logger.info(
569→          `Reply sent for message ${messageId}. outId=${routed?.outboundId || "unknown"} target=${routed?.targetJid || chatJid} usedFallback=${Boolean(routed?.usedFallback)} verified=${routed?.verified !== false}.`,
570→        );
571→      } else {
572→        this.logger.warn(
573→          `Agent returned empty reply for message ${messageId}; sending fallback guidance.`,
574→        );
575→        const fallbackText =
576→          "I could not produce a response for that message. Please rephrase your request in one sentence.";
577→        await this.sendReplyWithRouting({
578→          incomingJid: chatJid,
579→          inboundMessageId: messageId,
580→          replyText: fallbackText,
581→          fromMe: Boolean(baileysMsg.key.fromMe),
582→        });
583→      }
584→    } catch (error) {
585→      this.logger.error(`Message handling failed: ${error.message}`);
586→      try {
587→        const chatJid = baileysMsg?.key?.remoteJid;
588→        const inboundId = baileysMsg?.key?.id || `${Date.now()}`;
589→        if (!chatJid) return;
590→        const errorText =
591→          "I encountered an internal error while processing your request. Please try again.";
592→        await this.sendReplyWithRouting({
593→          incomingJid: chatJid,
594→          inboundMessageId: inboundId,
595→          replyText: errorText,
596→          fromMe: Boolean(baileysMsg?.key?.fromMe),
597→        });
598→      } catch (sendError) {
599→        this.logger.error(`Failed to send error message: ${sendError.message}`);
600→      }
601→    }
602→  }
603→
604→  async extractAttachments(baileysMsg, normalizedMessage) {
605→    const attachments = [];
606→    if (!normalizedMessage) return attachments;
607→
608→    if (normalizedMessage.imageMessage) {
609→      const buffer = await downloadMediaMessage(
610→        baileysMsg,
611→        "buffer",
612→        {},
613→        { logger: pino({ level: "silent" }) },
614→      );
615→      const imageMime = normalizedMessage.imageMessage.mimetype || "image/jpeg";
616→      const fileName = makeFileNameFromMime(
617→        baileysMsg.key.id || "image",
618→        "image",
619→        imageMime,
620→      );
621→      const targetPath = path.join(this.config.paths.inbox, fileName);
622→      await fs.writeFile(targetPath, buffer);
623→      attachments.push({
624→        type: "image",
625→        path: targetPath,
626→        mime: imageMime,
627→        originalName: fileName,
628→      });
629→    }
630→
631→    if (normalizedMessage.documentMessage) {
632→      const buffer = await downloadMediaMessage(
633→        baileysMsg,
634→        "buffer",
635→        {},
636→        { logger: pino({ level: "silent" }) },
637→      );
638→      const docMime =
639→        normalizedMessage.documentMessage.mimetype ||
640→        "application/octet-stream";
641→      const originalName =
642→        normalizedMessage.documentMessage.fileName ||
643→        makeFileNameFromMime(baileysMsg.key.id || "document", "document", docMime);
644→      const safeName = originalName.replace(/[<>:"/\\|?*\u0000-\u001F]/g, "_");
645→      const targetPath = path.join(
646→        this.config.paths.inbox,
647→        `${compactTimestamp()}_${safeName}`,
648→      );
